import {
  AdditionalCardSlice,
  createAdditionalCardSlice,
} from '@semparar/mf-app-fintech-card-place/src/services/additionalCard/store';
import {
  createSearchSlice,
  createSnackbarSlice,
  SnackbarSlice,
  type SearchSlice,
} from '@semparar/mf-app-price-comparison';
import { createChatSlice, ChatSlice } from '@semparar/mf-app-searchai/src/services/searchai';
import { createUserSlice, UserSlice } from '@semparar/mf-app-user/src/newArch/user';
import { create, type StateCreator } from 'zustand';
import { createJSONStorage, devtools, persist } from 'zustand/middleware';
import { immer } from 'zustand/middleware/immer';

import storage from '~/redux/store/storage';
import { AppsFlyerSlice, createAppsFlyerSlice } from '~/services/appsflyer/store/appsFlyerSlice';
import { createDeepLinkSlice, DeepLinkSlice } from '~/services/deeplink/store/deepLinkSlice';

export type RootStore = UserSlice &
  SearchSlice &
  SnackbarSlice &
  DeepLinkSlice &
  AppsFlyerSlice &
  ChatSlice &
  AdditionalCardSlice;

type Slice<T> = StateCreator<RootStore, [], [], T>;
const asSlice = <T>(slice: StateCreator<RootStore, [], [], T>) => slice as Slice<T>;

export const useRootStore = create<RootStore>()(
  devtools(
    persist(
      immer((...a) => ({
        ...asSlice<UserSlice>(createUserSlice)(...a),
        ...asSlice<SearchSlice>(createSearchSlice)(...a),
        ...asSlice<SnackbarSlice>(createSnackbarSlice)(...a),
        ...asSlice<DeepLinkSlice>(createDeepLinkSlice)(...a),
        ...asSlice<AppsFlyerSlice>(createAppsFlyerSlice)(...a),
        ...asSlice<AdditionalCardSlice>(createAdditionalCardSlice)(...a),
        ...asSlice<ChatSlice>(createChatSlice)(...a),
      })),
      {
        name: 'root-storage',
        storage: createJSONStorage(() => storage),
        partialize: (s) => ({
          user: s.user,
          additionalCard: s.additionalCard,
          chat: s.chat,
        }),
        merge: (persisted, current) => ({ ...current, ...(persisted as Partial<RootStore>) }),
      }
    ),
    { name: 'RootStore' }
  )
);

