import type { StateCreator } from 'zustand';

import type { AppsFlyerActions, AppsFlyerState } from '../Models';

export type AppsFlyerSlice = {
  appsFlyer: AppsFlyerState;
  appsFlyerActions: AppsFlyerActions;
};

const initialAppsFlyerState: AppsFlyerState = {
  uid: '',
};

export const createAppsFlyerSlice: StateCreator<AppsFlyerSlice, [], [], AppsFlyerSlice> = (
  set
) => ({
  appsFlyer: initialAppsFlyerState,

  appsFlyerActions: {
    setAppsFlyer: (data) =>
      set((state) => ({
        appsFlyer: {
          ...state.appsFlyer,
          ...data,
        },
      })),

    reset: () =>
      set(() => ({
        appsFlyer: initialAppsFlyerState,
      })),
  },
});

